import { match } from "arktype";

const handler = match({
    "{ status: 'success', data: object }": (payload) => `OK: ${JSON.stringify(payload.data)}`,
    "{ status: 'error', code: number, reason: string }": (payload) => `ERR ${payload.code} ${payload.reason}`,
    "{ status: 'pending' }": () => "PENDING",
    default: "assert"
});

console.log(handler({ status: 'pending' }));
console.log(handler({ status: 'success', data: { a: 1 } }));
console.log(handler({ status: 'error', code: 500, reason: "Fail" }));
try {
    handler({ status: 'unknown' });
} catch (e) {
    console.log("Caught:", e.message);
}

